declare const process: any;

const fs = require("node:fs");
const path = require("node:path");

const argv = process.argv.slice(2);

function showHelp(): void {
  console.log(`
Usage: todo <command> [options]

Commands:
  list --data <path>          List all tasks
  add <title> --data <path>   Add a new task
  done <id> --data <path>     Mark a task as done
  remove <id> --data <path>   Remove a task

Options:
  --data <path>   Path to the JSON file storing tasks (required)
`);
}

function parseArgs(args: string[]): { command: string; title?: string; id?: string; dataPath?: string } {
  const result: any = {};
  const commands = args.slice();
  const dataPathIdx = commands.findIndex(arg => arg === "--data");
  if (dataPathIdx === -1) {
    result.error = "Missing --data argument";
    return result;
  }
  if (dataPathIdx === commands.length - 1) {
    result.error = "Missing data path after --data";
    return result;
  }
  const dataPath = commands[dataPathIdx + 1];
  result.dataPath = dataPath;
  // Determine command and arguments before --data
  const beforeData = commands.slice(0, dataPathIdx);
  if (beforeData.length === 0) {
    result.error = "No command provided";
    return result;
  }
  const command = beforeData[0];
  result.command = command;
  if (command === "add" && beforeData.length >= 2) {
    result.title = beforeData[1];
  } else if (command === "done" && beforeData.length >= 2) {
    result.id = beforeData[1];
  } else if (command === "remove" && beforeData.length >= 2) {
    result.id = beforeData[1];
  } else if (command === "list" && beforeData.length > 1) {
    result.error = "list command does not take arguments";
  } else if (command !== "list" && beforeData.length > 1) {
    result.error = `Command ${command} does not take extra arguments`;
  }
  return result;
}

function outputResult(result: any): void {
  if (result.error) {
    console.error(result.error);
    process.exit(1);
  }
  console.log(JSON.stringify(result));
}

function main() {
  if (argv.length === 0) {
    showHelp();
    process.exit(1);
  }
  const parsed = parseArgs(argv);
  if (parsed.error) {
    console.error(parsed.error);
    process.exit(1);
  }
  const { command, title, id, dataPath } = parsed;
  if (!dataPath) {
    console.error("Missing --data argument");
    process.exit(1);
  }
  const store = new (require("./store")).TaskStore(dataPath);
  let output: any = {};
  switch (command) {
    case "list":
      output = { ok: true, tasks: store.list() };
      break;
    case "add":
      output = { ok: true, task: store.add(title!); }
      break;
    case "done":
      output = { ok: true, task: store.done(id!); }
      break;
    case "remove":
      output = { ok: true, task: store.remove(id!); }
      break;
    default:
      console.error(`Unknown command: ${command}`);
      process.exit(1);
  }
  outputResult(output);
}

main();
